const topic = String(msg.topic || "");

// Uplink: Local Edge telemetry z_# -> Cloud shared topic user_admin/gh_alpha/z_#
if (topic.startsWith("z_")) {
    const topicParts = topic.split('/');
    const metricName = topicParts[topicParts.length - 1];
    const allowedTelemetry = ["temp", "humidity", "soil", "pump_status"];
    if (!allowedTelemetry.includes(metricName)) return null;

    const rawValue = parseFloat(msg.payload);
    if (isNaN(rawValue)) return null;

    let unit = "";
    if (metricName === "temp") unit = "Cel";
    else if (metricName === "humidity" || metricName === "soil") unit = "%RH";
    else if (metricName === "pump_status") unit = "boolean";

    const senml = {
        bn: "user_admin/gh_alpha/" + topic + "/",
        e: [
            {
                n: metricName,
                u: unit,
                v: rawValue,
                t: Math.floor(Date.now() / 1000)
            }
        ]
    };

    msg.payload = senml;
    msg.topic = "user_admin/gh_alpha/" + topic;
    return [msg, null];
}

// Downlink: Cloud command/config user_admin/gh_alpha/z_#/r_#/(pump|config...) -> Local z_#/r_#/(pump|config...)
const commandMatch = topic.match(/^user_admin\/gh_alpha\/(z_[^/]+)\/(r_[^/]+)\/pump$/);
if (commandMatch) {
    const zPart = commandMatch[1];
    const rPart = commandMatch[2];
    msg.topic = `${zPart}/${rPart}/pump`;
    msg.payload = String(msg.payload ?? "TOGGLE");
    return [null, msg];
}

const configMatch = topic.match(/^user_admin\/gh_alpha\/(z_[^/]+)\/(r_[^/]+)\/config(?:\/(.*))?$/);
if (configMatch) {
    const zPart = configMatch[1];
    const rPart = configMatch[2];
    const configSuffix = configMatch[3];
    msg.topic = configSuffix ? `${zPart}/${rPart}/config/${configSuffix}` : `${zPart}/${rPart}/config`;
    if (typeof msg.payload !== "string") {
        msg.payload = JSON.stringify(msg.payload);
    }
    return [null, msg];
}

return null;
